    63→/// Configuration for the routing engine.
    64→#[derive(Debug, Clone, Serialize, Deserialize)]
    65→pub struct RouterConfig {
    66→    /// Enable subscription quota preference
    67→    pub prefer_subscription: bool,
    68→
    69→    /// Fallback timeout in seconds
    70→    pub fallback_timeout_secs: u64,
    71→
    72→    /// Enable load balancing across same-tier models
    73→    pub enable_load_balancing: bool,
    74→
    75→    /// Premium tier models
    76→    pub premium_models: Vec<ModelConfig>,
    77→
    78→    /// Standard tier models
    79→    pub standard_models: Vec<ModelConfig>,
    80→
    81→    /// Budget tier models
    82→    pub budget_models: Vec<ModelConfig>,
    83→}
    84→
    85→impl Default for RouterConfig {
    86→    fn default() -> Self {
    87→        Self {
    88→            prefer_subscription: true,
    89→            fallback_timeout_secs: DEFAULT_FALLBACK_TIMEOUT_SECS,
    90→            enable_load_balancing: true,
    91→            premium_models: vec![
    92→                ModelConfig::new("claude-opus-4", "Claude Opus 4", true),
    93→                ModelConfig::new("o1", "OpenAI O1", false),
    94→                ModelConfig::new("glm-5", "GLM-5", true),
    95→            ],
    96→            standard_models: vec![
    97→                ModelConfig::new("claude-sonnet-4", "Claude Sonnet 4", true),
    98→                ModelConfig::new("gpt-4", "GPT-4", false),
    99→                ModelConfig::new("qwen-2.5", "Qwen 2.5", false),
   100→            ],
   101→            budget_models: vec![
   102→                ModelConfig::new("claude-haiku-4", "Claude Haiku 4", true),
   103→                ModelConfig::new("gpt-3.5", "GPT-3.5", false),
   104→                ModelConfig::new("deepseek-coder", "DeepSeek Coder", false),
   105→            ],
   106→        }
   107→    }
   108→}
   109→
   110→impl RouterConfig {
   111→    /// Create a new router configuration with defaults.
   112→    pub fn new() -> Self {
   113→        Self::default()
   114→    }
   115→
   116→    /// Get models for a specific tier.
   117→    pub fn models_for_tier(&self, tier: WorkerTier) -> &[ModelConfig] {
   118→        match tier {
   119→            WorkerTier::Premium => &self.premium_models,
   120→            WorkerTier::Standard => &self.standard_models,
   121→            WorkerTier::Budget => &self.budget_models,
   122→        }
   123→    }
   124→
   125→    /// Load configuration from a YAML file.
   126→    pub fn from_yaml(path: &std::path::Path) -> Result<Self, RouterError> {
   127→        let content = std::fs::read_to_string(path)
   128→            .map_err(|e| RouterError::ConfigLoad {
   129→                path: path.to_path_buf(),
   130→                source: e,
   131→            })?;
   132→        let config: Self = serde_yaml::from_str(&content)
   133→            .map_err(|e| RouterError::ConfigParse {
   134→                message: e.to_string(),
   135→            })?;
   136→        config.validate()?;
   137→        Ok(config)
   138→    }
   139→
   140→    /// Validate the configuration.
   141→    pub fn validate(&self) -> Result<(), RouterError> {
   142→        if self.premium_models.is_empty() {
   143→            return Err(RouterError::ConfigValidation {
   144→                message: "At least one premium model is required".to_string(),
   145→            });
   146→        }
   147→        if self.standard_models.is_empty() {
   148→            return Err(RouterError::ConfigValidation {
   149→                message: "At least one standard model is required".to_string(),
   150→            });
   151→        }
   152→        if self.budget_models.is_empty() {
   153→            return Err(RouterError::ConfigValidation {
   154→                message: "At least one budget model is required".to_string(),
   155→            });
   156→        }
   157→        Ok(())
   158→    }
   159→}
