   179→    pub cost_per_million_input: f64,
   180→
   181→    /// Cost per million output tokens in USD
   182→    #[serde(default)]
   183→    pub cost_per_million_output: f64,
   184→}
   185→
   186→fn default_max_tokens() -> u32 {
   187→    128000
   188→}
   189→
   190→impl ModelConfig {
   191→    /// Create a new model configuration.
   192→    pub fn new(id: impl Into<String>, name: impl Into<String>, has_subscription: bool) -> Self {
   193→        Self {
   194→            id: id.into(),
   195→            name: name.into(),
   196→            has_subscription,
   197→            max_tokens: default_max_tokens(),
   198→            cost_per_million_input: 0.0,
   199→            cost_per_million_output: 0.0,
   200→        }
   201→    }
   202→
   203→    /// Set the maximum tokens.
   204→    pub fn with_max_tokens(mut self, max_tokens: u32) -> Self {
   205→        self.max_tokens = max_tokens;
