   217→/// Subscription quota status for a model.
   218→#[derive(Debug, Clone, Default)]
   219→pub struct SubscriptionQuota {
   220→    /// Total quota in tokens
   221→    pub total_tokens: u64,
   222→
   223→    /// Used tokens
   224→    pub used_tokens: u64,
   225→
   226→    /// Quota reset time (for use-or-lose subscriptions)
   227→    pub reset_at: Option<DateTime<Utc>>,
   228→}
   229→
   230→impl SubscriptionQuota {
   231→    /// Create a new subscription quota.
   232→    pub fn new(total_tokens: u64, used_tokens: u64) -> Self {
   233→        Self {
   234→            total_tokens,
   235→            used_tokens,
   236→            reset_at: None,
   237→        }
   238→    }
   239→
   240→    /// Create with reset time.
   241→    pub fn with_reset(mut self, reset_at: DateTime<Utc>) -> Self {
   242→        self.reset_at = Some(reset_at);
   243→        self
   244→    }
   245→
   246→    /// Get remaining tokens.
   247→    pub fn remaining(&self) -> u64 {
   248→        self.total_tokens.saturating_sub(self.used_tokens)
   249→    }
   250→
   251→    /// Get usage percentage.
   252→    pub fn usage_percent(&self) -> f64 {
   253→        if self.total_tokens == 0 {
   254→            return 0.0;
   255→        }
   256→        (self.used_tokens as f64 / self.total_tokens as f64) * 100.0
   257→    }
   258→
   259→    /// Check if quota is urgent (should use before reset).
   260→    pub fn is_urgent(&self) -> bool {
   261→        if let Some(reset_at) = self.reset_at {
   262→            let now = Utc::now();
   263→            let time_until_reset = reset_at.signed_duration_since(now);
   264→            // Urgent if less than 24 hours until reset and still have quota
   265→            time_until_reset.num_hours() < 24 && self.remaining() > 0
   266→        } else {
   267→            false
   268→        }
   269→    }
   270→
   271→    /// Check if quota is available.
   272→    pub fn is_available(&self) -> bool {
   273→        self.remaining() > 0
   274→    }
   275→}
