   877→    /// Get all available models for a tier.
   878→    pub fn available_models(&self, tier: WorkerTier) -> Vec<&ModelConfig> {
   879→        self.config
   880→            .models_for_tier(tier)
   881→            .iter()
   882→            .filter(|m| self.is_model_available(&m.id))
