   886→    /// Check health of all models.
   887→    pub fn health_check(&self) -> HashMap<String, ModelHealth> {
   888→        let mut health = HashMap::new();
   889→
   890→        for (model_id, avail) in &self.availability {
   891→            let quota = self.quotas.get(model_id);
   892→            health.insert(
   893→                model_id.clone(),
   894→                ModelHealth {
   895→                    is_available: avail.is_available,
   896→                    active_workers: avail.active_workers,
   897→                    avg_latency_ms: avail.avg_latency_ms,
   898→                    last_error: avail.last_error.clone(),
   899→                    quota_remaining: quota.map(|q| q.remaining()),
   900→                    quota_urgent: quota.map(|q| q.is_urgent()).unwrap_or(false),
   901→                },
   902→            );
   903→        }
   904→
   905→        health
   906→    }
   907→}
