     1→//! Cost analytics panel for the FORGE TUI.
     2→//!
     3→//! This module provides rich cost visualization with:
     4→//! - Per-model breakdown table
     5→//! - Sparkline trends
     6→//! - Cost breakdown chart by priority
     7→//! - Summary stats
     8→//! - Color-coded budget alerts
     9→//! - Optimization recommendations
    10→//! - Savings achieved display
    11→
    12→use chrono::{NaiveDate, Utc};
    13→use ratatui::{
    14→    buffer::Buffer,
    15→    layout::{Constraint, Direction, Layout, Rect},
    16→    style::{Color, Modifier, Style},
    17→    text::{Line, Span},
    18→    widgets::{Block, BorderType, Borders, Paragraph, Row, Table, Widget},
    19→};
    20→
    21→use crate::log_watcher::RealtimeMetrics;
    22→use forge_cost::{
    23→    CostBreakdown, DailyCost, ModelCost, OptimizationRecommendation, ProjectedCost,
    24→    WorkerCostBreakdown,
    25→};
    26→
    27→/// Budget alert severity levels.
    28→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    29→pub enum BudgetAlertLevel {
    30→    /// Under budget - everything is fine
    31→    Normal,
    32→    /// Approaching budget threshold (70-90%)
    33→    Warning,
    34→    /// At or exceeding budget (90%+)
    35→    Critical,
    36→    /// Budget exceeded
    37→    Exceeded,
    38→}
    39→
    40→impl BudgetAlertLevel {
    41→    /// Get the color for this alert level.
    42→    pub fn color(&self) -> Color {
    43→        match self {
    44→            BudgetAlertLevel::Normal => Color::Green,
    45→            BudgetAlertLevel::Warning => Color::Yellow,
    46→            BudgetAlertLevel::Critical => Color::LightRed,
    47→            BudgetAlertLevel::Exceeded => Color::Red,
    48→        }
    49→    }
    50→
    51→    /// Get icon for this alert level.
    52→    pub fn icon(&self) -> &'static str {
    53→        match self {
    54→            BudgetAlertLevel::Normal => "✓",
    55→            BudgetAlertLevel::Warning => "⚠",
    56→            BudgetAlertLevel::Critical => "⚠",
    57→            BudgetAlertLevel::Exceeded => "✗",
    58→        }
    59→    }
    60→
    61→    /// Get description for this alert level.
    62→    pub fn description(&self) -> &'static str {
    63→        match self {
    64→            BudgetAlertLevel::Normal => "On Track",
    65→            BudgetAlertLevel::Warning => "Approaching Limit",
    66→            BudgetAlertLevel::Critical => "Near Limit",
    67→            BudgetAlertLevel::Exceeded => "Over Budget",
    68→        }
    69→    }
    70→
    71→    /// Determine alert level from usage percentage.
    72→    pub fn from_percentage(pct: f64) -> Self {
    73→        if pct >= 100.0 {
    74→            BudgetAlertLevel::Exceeded
    75→        } else if pct >= 90.0 {
    76→            BudgetAlertLevel::Critical
    77→        } else if pct >= 70.0 {
    78→            BudgetAlertLevel::Warning
    79→        } else {
    80→            BudgetAlertLevel::Normal
    81→        }
    82→    }
    83→}
    84→
    85→/// Budget configuration for cost tracking.
    86→#[derive(Debug, Clone)]
    87→pub struct BudgetConfig {
    88→    /// Monthly budget limit in USD
    89→    pub monthly_limit: f64,
    90→    /// Daily budget limit in USD (optional, calculated from monthly if not set)
    91→    pub daily_limit: Option<f64>,
    92→    /// Warning threshold percentage (default 70%)
    93→    pub warning_threshold: f64,
    94→    /// Critical threshold percentage (default 90%)
    95→    pub critical_threshold: f64,
    96→}
    97→
    98→impl Default for BudgetConfig {
    99→    fn default() -> Self {
   100→        Self {
   101→            monthly_limit: 500.0, // $500/month default
   102→            daily_limit: None,
   103→            warning_threshold: 80.0,  // 80% triggers warning
   104→            critical_threshold: 90.0,
   105→        }
   106→    }
   107→}
   108→
   109→impl BudgetConfig {
   110→    /// Create a new budget config with a monthly limit.
   111→    pub fn new(monthly_limit: f64) -> Self {
   112→        Self {
   113→            monthly_limit,
   114→            ..Default::default()
   115→        }
   116→    }
   117→
   118→    /// Set daily limit.
   119→    pub fn with_daily_limit(mut self, limit: f64) -> Self {
   120→        self.daily_limit = Some(limit);
   121→        self
   122→    }
   123→
   124→    /// Get effective daily limit (calculated or explicit).
   125→    pub fn effective_daily_limit(&self) -> f64 {
   126→        self.daily_limit.unwrap_or(self.monthly_limit / 30.0)
   127→    }
   128→
   129→    /// Get alert level for current spending.
   130→    pub fn get_monthly_alert(&self, current_spend: f64) -> BudgetAlertLevel {
   131→        let pct = (current_spend / self.monthly_limit) * 100.0;
   132→        BudgetAlertLevel::from_percentage(pct)
   133→    }
   134→
   135→    /// Get alert level for daily spending.
   136→    pub fn get_daily_alert(&self, current_spend: f64) -> BudgetAlertLevel {
   137→        let limit = self.effective_daily_limit();
   138→        let pct = (current_spend / limit) * 100.0;
   139→        BudgetAlertLevel::from_percentage(pct)
   140→    }
   141→}
