   143→/// Cost data prepared for TUI display.
   144→#[derive(Debug, Default)]
   145→pub struct CostPanelData {
   146→    /// Today's costs
   147→    pub today: Option<DailyCost>,
   148→    /// This week's costs (last 7 days)
   149→    pub week: Option<DailyCost>,
   150→    /// Current month's total cost
   151→    pub monthly_total: f64,
   152→    /// Monthly cost by model
   153→    pub monthly_by_model: Vec<ModelCost>,
   154→    /// Daily costs for trend (last 7-14 days)
   155→    pub daily_trend: Vec<(NaiveDate, f64)>,
   156→    /// Projected costs
   157→    pub projected: Option<ProjectedCost>,
   158→    /// Budget configuration
   159→    pub budget: BudgetConfig,
   160→    /// Optimization recommendations
   161→    pub recommendations: Vec<OptimizationRecommendation>,
   162→    /// Total potential savings from optimizations
   163→    pub potential_savings: f64,
   164→    /// Savings achieved from previous optimizations
   165→    pub savings_achieved: f64,
   166→    /// Subscription utilization percentage
   167→    pub subscription_utilization: f64,
   168→    /// Real-time metrics from log parsing
   169→    pub realtime: RealtimeMetrics,
   170→    /// Per-worker cost breakdown
   171→    pub worker_costs: Vec<WorkerCostBreakdown>,
   172→    /// Total cost for current session
   173→    pub session_total: f64,
   174→    /// Threshold for marking workers as expensive (USD)
   175→    pub expensive_threshold: f64,
   176→    /// Last update timestamp
   177→    pub last_update: Option<chrono::DateTime<Utc>>,
   178→    /// Whether data is loading
   179→    pub is_loading: bool,
   180→    /// Error message if any
   181→    pub error: Option<String>,
   182→}
   183→
   184→impl CostPanelData {
   185→    /// Create new empty cost panel data.
   186→    pub fn new() -> Self {
   187→        Self::default()
   188→    }
   189→
   190→    /// Set loading state.
   191→    pub fn loading() -> Self {
   192→        Self {
   193→            is_loading: true,
   194→            ..Default::default()
   195→        }
   196→    }
   197→
   198→    /// Set error state.
   199→    pub fn with_error(error: impl Into<String>) -> Self {
   200→        Self {
   201→            error: Some(error.into()),
   202→            ..Default::default()
   203→        }
   204→    }
   205→
   206→    /// Update with today's cost data.
   207→    pub fn set_today(&mut self, today: DailyCost) {
   208→        self.today = Some(today);
   209→        self.last_update = Some(Utc::now());
   210→        self.is_loading = false;
   211→    }
   212→
   213→    /// Update with week's cost data.
   214→    pub fn set_week(&mut self, week: DailyCost) {
   215→        self.week = Some(week);
   216→    }
   217→
   218→    /// Update with monthly data.
   219→    pub fn set_monthly(&mut self, total: f64, by_model: Vec<ModelCost>) {
   220→        self.monthly_total = total;
   221→        self.monthly_by_model = by_model;
   222→    }
   223→
   224→    /// Update with daily trend data.
   225→    pub fn set_daily_trend(&mut self, trend: Vec<(NaiveDate, f64)>) {
   226→        self.daily_trend = trend;
   227→    }
   228→
   229→    /// Update with projected costs.
   230→    pub fn set_projected(&mut self, projected: ProjectedCost) {
   231→        self.projected = Some(projected);
   232→    }
   233→
   234→    /// Set budget configuration.
   235→    pub fn set_budget(&mut self, budget: BudgetConfig) {
   236→        self.budget = budget;
   237→    }
   238→
   239→    /// Set optimization recommendations.
   240→    pub fn set_recommendations(&mut self, recommendations: Vec<OptimizationRecommendation>) {
   241→        self.potential_savings = recommendations.iter().map(|r| r.estimated_savings).sum();
   242→        self.recommendations = recommendations;
   243→    }
   244→
   245→    /// Set savings achieved.
   246→    pub fn set_savings_achieved(&mut self, savings: f64) {
   247→        self.savings_achieved = savings;
   248→    }
   249→
   250→    /// Set subscription utilization.
   251→    pub fn set_subscription_utilization(&mut self, utilization: f64) {
   252→        self.subscription_utilization = utilization;
   253→    }
   254→
   255→    /// Set worker cost breakdown.
   256→    pub fn set_worker_costs(&mut self, workers: Vec<WorkerCostBreakdown>) {
   257→        self.worker_costs = workers;
   258→    }
   259→
   260→    /// Set session total cost.
   261→    pub fn set_session_total(&mut self, total: f64) {
   262→        self.session_total = total;
   263→    }
   264→
   265→    /// Set expensive threshold.
   266→    pub fn set_expensive_threshold(&mut self, threshold: f64) {
   267→        self.expensive_threshold = threshold;
   268→        // Mark workers as expensive based on new threshold
   269→        for worker in &mut self.worker_costs {
   270→            worker.is_expensive = worker.total_cost_usd >= self.expensive_threshold;
   271→        }
   272→    }
   273→
   274→    /// Get total cost from all workers.
   275→    pub fn workers_total_cost(&self) -> f64 {
   276→        self.worker_costs.iter().map(|w| w.total_cost_usd).sum()
   277→    }
   278→
   279→    /// Get count of expensive workers.
   280→    pub fn expensive_worker_count(&self) -> usize {
   281→        self.worker_costs.iter().filter(|w| w.is_expensive).count()
   282→    }
   283→
   284→    /// Check if we have worker cost data.
   285→    pub fn has_worker_costs(&self) -> bool {
   286→        !self.worker_costs.is_empty()
   287→    }
   288→
   289→    /// Set real-time metrics from log parsing.
   290→    pub fn set_realtime(&mut self, realtime: RealtimeMetrics) {
   291→        self.realtime = realtime;
   292→    }
   293→
   294→    /// Check if we have optimization recommendations.
   295→    pub fn has_recommendations(&self) -> bool {
   296→        !self.recommendations.is_empty()
   297→    }
   298→
   299→    /// Get the top recommendation by priority.
   300→    pub fn top_recommendation(&self) -> Option<&OptimizationRecommendation> {
   301→        self.recommendations.first()
   302→    }
   303→
   304→    /// Get today's total cost.
   305→    pub fn today_total(&self) -> f64 {
   306→        self.today.as_ref().map(|t| t.total_cost_usd).unwrap_or(0.0)
   307→    }
   308→
   309→    /// Get today's call count.
   310→    pub fn today_calls(&self) -> i64 {
   311→        self.today.as_ref().map(|t| t.call_count).unwrap_or(0)
   312→    }
   313→
   314→    /// Get today's token count.
   315→    pub fn today_tokens(&self) -> i64 {
   316→        self.today.as_ref().map(|t| t.total_tokens).unwrap_or(0)
   317→    }
   318→
   319→    /// Get week's total cost.
   320→    pub fn week_total(&self) -> f64 {
   321→        self.week.as_ref().map(|w| w.total_cost_usd).unwrap_or(0.0)
   322→    }
   323→
   324→    /// Get week's call count.
   325→    pub fn week_calls(&self) -> i64 {
   326→        self.week.as_ref().map(|w| w.call_count).unwrap_or(0)
   327→    }
   328→
   329→    /// Get week's token count.
   330→    pub fn week_tokens(&self) -> i64 {
   331→        self.week.as_ref().map(|w| w.total_tokens).unwrap_or(0)
   332→    }
   333→
   334→    /// Get monthly budget usage percentage.
   335→    pub fn monthly_usage_pct(&self) -> f64 {
   336→        if self.budget.monthly_limit > 0.0 {
   337→            (self.monthly_total / self.budget.monthly_limit) * 100.0
   338→        } else {
   339→            0.0
   340→        }
   341→    }
   342→
   343→    /// Get daily budget usage percentage.
   344→    pub fn daily_usage_pct(&self) -> f64 {
   345→        let limit = self.budget.effective_daily_limit();
   346→        if limit > 0.0 {
   347→            (self.today_total() / limit) * 100.0
   348→        } else {
   349→            0.0
   350→        }
   351→    }
   352→
   353→    /// Get monthly budget alert level.
   354→    pub fn monthly_alert(&self) -> BudgetAlertLevel {
   355→        self.budget.get_monthly_alert(self.monthly_total)
   356→    }
   357→
   358→    /// Get daily budget alert level.
   359→    pub fn daily_alert(&self) -> BudgetAlertLevel {
   360→        self.budget.get_daily_alert(self.today_total())
   361→    }
   362→
   363→    /// Check if we have any data.
   364→    pub fn has_data(&self) -> bool {
   365→        self.today.is_some()
   366→            || self.week.is_some()
   367→            || self.monthly_total > 0.0
   368→            || !self.monthly_by_model.is_empty()
   369→            || self.realtime.has_data()
   370→    }
   371→}
