   965→    fn render(self, area: Rect, buf: &mut Buffer) {
   966→        // Enhanced focus indicator: "▶" arrow for focused (clearer than diamond), "▪" for unfocused
   967→        let focus_icon = if self.focused { "▶" } else { "▪" };
   968→
   969→        // Border type: Double border for focused (highly visible), Normal for unfocused
   970→        let border_type = if self.focused {
   971→            BorderType::Double
   972→        } else {
   973→            BorderType::Plain
   974→        };
   975→
   976→        // Border style: bright cyan with bold for focused, dim for unfocused
   977→        let border_style = if self.focused {
   978→            Style::default()
   979→                .fg(Color::Cyan)
   980→                .add_modifier(Modifier::BOLD)
   981→        } else {
   982→            Style::default().fg(Color::DarkGray)
   983→        };
   984→
   985→        // Title style: bold + underlined for focused, dim for unfocused
   986→        let title_style = if self.focused {
   987→            Style::default()
   988→                .fg(Color::Cyan)
   989→                .add_modifier(Modifier::BOLD | Modifier::UNDERLINED)
   990→        } else {
   991→            Style::default().fg(Color::Rgb(80, 80, 80))
   992→        };
   993→
   994→        let block = Block::default()
   995→            .borders(Borders::ALL)
   996→            .border_type(border_type)
   997→            .border_style(border_style)
   998→            .title(Span::styled(
   999→                format!(" {} Cost Analytics ", focus_icon),
  1000→                title_style,
