                Span::raw("/call"),
            ]));
        }

        let paragraph = Paragraph::new(lines);
        paragraph.render(area, buf);
    }

    /// Render the model breakdown table.
    fn render_model_table(&self, area: Rect, buf: &mut Buffer) {
        // Get today's model breakdown or monthly
        let models: Vec<&CostBreakdown> = if let Some(ref today) = self.data.today {
            today.by_model.iter().collect()
        } else {
            Vec::new()
        };

        if models.is_empty() {
            let msg =
                Paragraph::new("No model data available").style(Style::default().fg(Color::Gray));
            msg.render(area, buf);
            return;
        }

        // Find max cost for scaling bars
        let max_cost = models
            .iter()
            .map(|m| m.total_cost_usd)
            .fold(0.0_f64, f64::max);

        // Build table rows
        let rows: Vec<Row> = models
            .iter()
            .take(6) // Limit to 6 models
            .map(|m| {
                let bar = render_bar(m.total_cost_usd, max_cost, 8, '▓', '░');
                Row::new(vec![
                    truncate_model_name(&m.model, 12),
                    format!("{:>3}", m.call_count),
                    format_tokens(m.input_tokens + m.output_tokens),
                    format_usd(m.total_cost_usd),
                    bar,
                ])
            })
            .collect();

        let header = Row::new(vec!["Model", "#", "Tokens", "Cost", ""])
            .style(
                Style::default()
                    .fg(Color::Gray)
                    .add_modifier(Modifier::BOLD),
            )
            .bottom_margin(0);

        let widths = [
            Constraint::Length(12),
            Constraint::Length(4),
            Constraint::Length(7),
            Constraint::Length(8),
            Constraint::Length(8),
        ];

        let table = Table::new(rows, widths).header(header).column_spacing(1);

        ratatui::widgets::Widget::render(table, area, buf);
    }

    /// Render the sparkline trend.
    fn render_trend(&self, area: Rect, buf: &mut Buffer) {
        if self.data.daily_trend.is_empty() {
            let msg = Paragraph::new("No trend data").style(Style::default().fg(Color::Gray));
            msg.render(area, buf);
            return;
        }

        let values: Vec<f64> = self.data.daily_trend.iter().map(|(_, v)| *v).collect();
        let sparkline = render_sparkline(&values, area.width.saturating_sub(10) as usize);

        // Get date range
        let first_date = self.data.daily_trend.first().map(|(d, _)| *d);
        let last_date = self.data.daily_trend.last().map(|(d, _)| *d);

        let mut lines = Vec::new();

        if let (Some(first), Some(last)) = (first_date, last_date) {
            lines.push(Line::from(vec![
                Span::raw("Trend "),
                Span::styled(
                    format!("{} - {}", first.format("%m/%d"), last.format("%m/%d")),
                    Style::default().fg(Color::Gray),
                ),
            ]));
        } else {
            lines.push(Line::from("Trend"));
        }

        lines.push(Line::from(Span::styled(
            sparkline,
            Style::default().fg(Color::Cyan),
        )));

        // Min/max labels
        let min_val = values.iter().cloned().fold(f64::MAX, f64::min);
        let max_val = values.iter().cloned().fold(0.0_f64, f64::max);
        lines.push(Line::from(vec![
            Span::styled(format_usd(min_val), Style::default().fg(Color::Green)),
            Span::raw(" - "),
            Span::styled(format_usd(max_val), Style::default().fg(Color::Red)),
        ]));

        let paragraph = Paragraph::new(lines);
        paragraph.render(area, buf);
    }

    /// Render optimization recommendations.
    fn render_recommendations(&self, area: Rect, buf: &mut Buffer) {
        if self.data.recommendations.is_empty() {
            let msg =
                Paragraph::new("No recommendations").style(Style::default().fg(Color::Gray));
            msg.render(area, buf);
            return;
        }

        let mut lines = Vec::new();

        // Show top 3 recommendations
        for rec in self.data.recommendations.iter().take(3) {
            let (icon, color) = match rec.recommendation_type {
                forge_cost::RecommendationType::AccelerateSubscription => ("🚀", Color::Cyan),
                forge_cost::RecommendationType::MaxOutSubscription => ("⚡", Color::Yellow),
                forge_cost::RecommendationType::ModelDowngrade => ("📉", Color::Blue),
                forge_cost::RecommendationType::EnableCaching => ("💾", Color::Green),
                forge_cost::RecommendationType::BatchTasks => ("📦", Color::Magenta),
                forge_cost::RecommendationType::OffPeakScheduling => ("🌙", Color::Blue),
                forge_cost::RecommendationType::SubscriptionDepleted => ("❌", Color::Red),
            };

            // Truncate title if too long
            let title = if rec.title.len() > 35 {
                format!("{}…", &rec.title[..32])
            } else {
                rec.title.clone()
            };

            lines.push(Line::from(vec![
                Span::styled(icon, Style::default().fg(color)),
                Span::raw(" "),
                Span::styled(title, Style::default().fg(Color::White)),
            ]));

            // Show savings if significant
            if rec.estimated_savings > 0.01 {
                lines.push(Line::from(vec![
                    Span::raw("   "),
                    Span::styled(
                        format!("Save {}", format_usd(rec.estimated_savings)),
                        Style::default().fg(Color::Green),
                    ),
                ]));
            }
        }

        let paragraph = Paragraph::new(lines);
        paragraph.render(area, buf);
    }

    /// Render worker cost breakdown.
    fn render_worker_costs(&self, area: Rect, buf: &mut Buffer) {
        if self.data.worker_costs.is_empty() {
            let msg = Paragraph::new("No worker data").style(Style::default().fg(Color::Gray));
            msg.render(area, buf);
            return;
        }

        // Find max cost for scaling bars
        let max_cost = self
            .data
            .worker_costs
            .iter()
            .map(|w| w.total_cost_usd)
            .fold(0.0_f64, f64::max);

        let mut lines = Vec::new();

        // Session total
        if self.data.session_total > 0.0 {
            lines.push(Line::from(vec![
                Span::styled("Session: ", Style::default().fg(Color::Gray)),
                Span::styled(
                    format_usd(self.data.session_total),
                    Style::default()
                        .fg(Color::Cyan)
                        .add_modifier(Modifier::BOLD),
                ),
            ]));
            lines.push(Line::from(""));
        }

        // Header
        lines.push(Line::from(vec![
            Span::styled("Worker", Style::default().fg(Color::Gray)),
            Span::raw("  "),
            Span::styled("#", Style::default().fg(Color::Gray)),
            Span::raw(" "),
            Span::styled("Cost", Style::default().fg(Color::Gray)),
            Span::raw("    "),
            Span::styled("Task", Style::default().fg(Color::Gray)),
        ]));

        // Show top workers (limit to fit area)
        let worker_limit = (area.height.saturating_sub(4) as usize).min(8);
        for worker in self.data.worker_costs.iter().take(worker_limit) {
            // Truncate worker ID
            let worker_id = if worker.worker_id.len() > 12 {
                format!("{}…", &worker.worker_id[..11])
            } else {
                worker.worker_id.clone()
            };

            // Color based on expense
            let cost_color = if worker.is_expensive {
                Color::LightRed
            } else if worker.total_cost_usd > max_cost * 0.5 {
                Color::Yellow
            } else {
                Color::Green
            };

            // Expense indicator
            let indicator = if worker.is_expensive { "⚠ " } else { "  " };

            // Task info
            let task = worker
                .bead_id
                .as_ref()
                .map(|t| {
                    if t.len() > 10 {
                        format!("{}…", &t[..9])
                    } else {
                        t.clone()
                    }
                })
                .unwrap_or_else(|| "-".to_string());

            lines.push(Line::from(vec![
                Span::styled(indicator, Style::default().fg(Color::LightRed)),
                Span::styled(
                    format!("{:<12}", worker_id),
                    Style::default().fg(Color::White),
                ),
                Span::raw(" "),
                Span::styled(
                    format!("{:>2}", worker.call_count.min(99)),
                    Style::default().fg(Color::Gray),
                ),
                Span::raw(" "),
                Span::styled(format_usd(worker.total_cost_usd), Style::default().fg(cost_color)),
                Span::raw("  "),
                Span::styled(task, Style::default().fg(Color::DarkGray)),
            ]));
        }

        // Summary line
        let expensive_count = self.data.expensive_worker_count();
        if expensive_count > 0 {
            lines.push(Line::from(""));
            lines.push(Line::from(vec![
                Span::styled(
                    format!("⚠ {} expensive", expensive_count),
                    Style::default().fg(Color::LightRed),
                ),
                Span::raw(" (≥"),
                Span::styled(
                    format_usd(self.data.expensive_threshold),
                    Style::default().fg(Color::Gray),
                ),
                Span::raw(")"),
            ]));
        }

        let paragraph = Paragraph::new(lines);
        paragraph.render(area, buf);
    }
}

impl Widget for CostPanel<'_> {
    fn render(self, area: Rect, buf: &mut Buffer) {
        // Enhanced focus indicator: "▶" arrow for focused (clearer than diamond), "▪" for unfocused
        let focus_icon = if self.focused { "▶" } else { "▪" };

        // Border type: Double border for focused (highly visible), Normal for unfocused
        let border_type = if self.focused {
            BorderType::Double
        } else {
            BorderType::Plain
        };

        // Border style: bright cyan with bold for focused, dim for unfocused
        let border_style = if self.focused {
            Style::default()
                .fg(Color::Cyan)
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default().fg(Color::DarkGray)
        };

        // Title style: bold + underlined for focused, dim for unfocused
        let title_style = if self.focused {
            Style::default()
                .fg(Color::Cyan)
                .add_modifier(Modifier::BOLD | Modifier::UNDERLINED)
        } else {
            Style::default().fg(Color::Rgb(80, 80, 80))
        };

        let block = Block::default()
            .borders(Borders::ALL)
            .border_type(border_type)
            .border_style(border_style)
            .title(Span::styled(
                format!(" {} Cost Analytics ", focus_icon),
                title_style,
            ));

        let inner = block.inner(area);
        block.render(area, buf);

        // Handle special states
        if self.data.is_loading {
            let loading =
                Paragraph::new("Loading cost data...").style(Style::default().fg(Color::Yellow));
            loading.render(inner, buf);
            return;
        }

        if let Some(ref error) = self.data.error {
            let err =
                Paragraph::new(format!("Error: {}", error)).style(Style::default().fg(Color::Red));
            err.render(inner, buf);
            return;
        }

        if !self.data.has_data() {
            let no_data = Paragraph::new(
                "No cost data available.\n\n\
                 Cost tracking requires:\n\
                 - forge-cost database initialized\n\
                 - Worker logs being parsed\n\n\
                 Run: forge costs init",
            )
            .style(Style::default().fg(Color::Gray));
            no_data.render(inner, buf);
            return;
        }

        // Layout: Summary | Worker Costs | Model Table | Trend | Recommendations
        let rec_height = if self.data.has_recommendations() { 5 } else { 0 };
        let worker_height = if self.data.has_worker_costs() { 8 } else { 0 };
        let layout = Layout::default()
            .direction(Direction::Vertical)
            .constraints([
                Constraint::Length(11),     // Summary (increased for week line)
                Constraint::Length(worker_height), // Worker costs
                Constraint::Min(5),         // Model table
                Constraint::Length(4),      // Trend sparkline
                Constraint::Length(rec_height), // Recommendations
            ])
            .split(inner);

        self.render_summary(layout[0], buf);
        if worker_height > 0 {
            self.render_worker_costs(layout[1], buf);
        }
        self.render_model_table(layout[2], buf);
        self.render_trend(layout[3], buf);
        if rec_height > 0 {
            self.render_recommendations(layout[4], buf);
        }
    }
}

